INSERT INTO quiz_questions (belt_id, question, options, correct_answer, type) VALUES\n('branca-cinza', 'Qual é a idade mínima exigida para o exame da faixa Branca/Cinza?', '["3 (três) anos","4 (quatro) anos","5 (cinco) anos","6 (seis) anos"]'::jsonb, '4 (quatro) anos', 'history'),\n('branca-cinza', 'Qual é a carência mínima de tempo na graduação anterior para prestar exame para a faixa Branca/Cinza?', '["1 (um) mês","3 (três) meses","6 (seis) meses","1 (um) ano"]'::jsonb, '3 (três) meses', 'history'),\n('branca-cinza', 'Qual é o termo japonês utilizado para a saudação em pé?', '["Za-Rei","Ritsu-Rei","Mokuso","Ukemi"]'::jsonb, 'Ritsu-Rei', 'vocab'),\n('branca-cinza', 'Qual é o termo japonês utilizado para a saudação ajoelhado?', '["Za-Rei","Ritsu-Rei","Shintai","Hajime"]'::jsonb, 'Za-Rei', 'vocab'),\n('branca-cinza', 'O que significa a palavra ''Sensei''?', '["Aluno","Professor","Árbitro","Escola de Judô"]'::jsonb, 'Professor', 'vocab'),\n('branca-cinza', 'O que é o Ushiro-Ukemi?', '["Queda para trás","Queda para o lado","Queda para frente","Rolamento"]'::jsonb, 'Queda para trás', 'technique'),\n('branca-cinza', 'O que é o Yoko-Ukemi?', '["Queda para trás","Queda para o lado","Queda para frente","Saudação em pé"]'::jsonb, 'Queda para o lado', 'technique'),\n('branca-cinza', 'Para a faixa Branca/Cinza, a partir de qual posição o Yoko-Ukemi deve ser executado?', '["Em pé","Em movimento","Posição deitado","Posição agachado"]'::jsonb, 'Posição deitado', 'technique'),\n('branca-cinza', 'Qual é a técnica de projeção (Nage-Waza) exigida para a faixa Branca/Cinza?', '["O-Soto-Gari","O-Uchi-Gari","Seoi-Nage","Uki-Goshi"]'::jsonb, 'O-Soto-Gari', 'technique'),\n('branca-cinza', 'Qual é a técnica de imobilização (Osae-Komi-Waza) exigida para a faixa Branca/Cinza?', '["Kuzure-Kesa-Gatame","Kesa-Gatame","Yoko-Shiho-Gatame","Kata-Gatame"]'::jsonb, 'Kesa-Gatame', 'technique'),\n('cinza', 'Qual a idade mínima exigida para a faixa Cinza?', '["4 (quatro) anos","5 (cinco) anos","6 (seis) anos","7 (sete) anos"]'::jsonb, '5 (cinco) anos', 'history'),\n('cinza', 'Quem é o criador do Judô?', '["Mitsuyo Maeda","Gichin Funakoshi","Jigoro Kano","Conde Koma"]'::jsonb, 'Jigoro Kano', 'history'),\n('cinza', 'Como se chamam as peças que compõem o local de treinamento?', '["Dojo","Tatami","Judogi","Obi"]'::jsonb, 'Tatami', 'vocab'),\n('cinza', 'Como se chama o uniforme do praticante de judô?', '["Tatami","Obi","Judogi","Uwagi"]'::jsonb, 'Judogi', 'vocab'),\n('cinza', 'Como se diz o número 1 em japonês?', '["Ichi","Ni","San","Shi"]'::jsonb, 'Ichi', 'vocab'),\n('cinza', 'Como se diz o número 2 em japonês?', '["Shi","Go","Ni","San"]'::jsonb, 'Ni', 'vocab'),\n('cinza', 'Como se diz o número 3 em japonês?', '["Ichi","Ni","San","Go"]'::jsonb, 'San', 'vocab'),\n('cinza', 'Como se diz o número 4 em japonês?', '["Shi","Roku","Hachi","Kyuu"]'::jsonb, 'Shi', 'vocab'),\n('cinza', 'Como se diz o número 5 em japonês?', '["San","Shi","Go","Juu"]'::jsonb, 'Go', 'vocab'),\n('cinza', 'Como se diz o número 10 em japonês?', '["Hachi","Kyuu","Juu","Roku"]'::jsonb, 'Juu', 'vocab'),\n('cinza', 'O que é Zenpo-Kaiten-Ukemi?', '["Queda para trás","Queda para frente com rolamento","Queda lateral","Queda amortecida em pé"]'::jsonb, 'Queda para frente com rolamento', 'technique'),\n('cinza', 'Qual nova técnica de Nage-Waza é introduzida na faixa Cinza (junto ao O-Soto-Gari)?', '["O-Uchi-Gari","Uki-Goshi","Seoi-Nage","Tai-Otoshi"]'::jsonb, 'O-Uchi-Gari', 'technique'),\n('cinza', 'Qual nova técnica de Osae-Komi-Waza é introduzida na faixa Cinza?', '["Kesa-Gatame","Kuzure-Kesa-Gatame","Yoko-Shiho-Gatame","Kami-Shiho-Gatame"]'::jsonb, 'Kuzure-Kesa-Gatame', 'technique'),\n('cinza', 'A partir de qual posição o Yoko-Ukemi deve ser executado no exame para a faixa Cinza?', '["Deitado","Agachado","Em movimento","Com rolamento"]'::jsonb, 'Agachado', 'technique'),\n('cinza-azul', 'Qual a idade mínima exigida para a faixa Cinza/Azul?', '["5 (cinco) anos","6 (seis) anos","7 (sete) anos","8 (oito) anos"]'::jsonb, '6 (seis) anos', 'history'),\n('cinza-azul', 'Qual o tempo de carência mínima na graduação anterior para a faixa Cinza/Azul?', '["3 (três) meses","6 (seis) meses","9 (nove) meses","1 (um) ano"]'::jsonb, '6 (seis) meses', 'history'),\n('cinza-azul', 'Qual foi a primeira escola de JUDÔ?', '["Tenjin Shinyo","Kito-Ryu","Kodokan","Butoku-kai"]'::jsonb, 'Kodokan', 'history'),\n('cinza-azul', 'O que significa o termo ''Matte''?', '["Começar","Parar","Terminou","Não se mova"]'::jsonb, 'Parar', 'vocab'),\n('cinza-azul', 'O que significa o comando ''Hajime''?', '["Parar","Terminou","Começar","Atenção"]'::jsonb, 'Começar', 'vocab'),\n('cinza-azul', 'O que significa ''Soremade''?', '["Parar","Começar","Terminou","Não se mova"]'::jsonb, 'Terminou', 'vocab'),\n('cinza-azul', 'O que significa ''Sonomama''?', '["Não se mova","Parar","Atenção","Começar"]'::jsonb, 'Não se mova', 'vocab'),\n('cinza-azul', 'O que significa ''Kiotsuke''?', '["Atenção, posição de sentido","Parar a luta","Terminou","Não se mova"]'::jsonb, 'Atenção, posição de sentido', 'vocab'),\n('cinza-azul', 'O que é cobrado sob o termo ''Kumi-Kata'' no exame?', '["Formas de saudação","Formas de pegar no Judogi","Formas de desequilíbrio","Formas de rolamento"]'::jsonb, 'Formas de pegar no Judogi', 'technique'),\n('cinza-azul', 'Qual nova técnica de Nage-Waza é introduzida na faixa Cinza/Azul?', '["Tai-Otoshi","Uki-Goshi","Seoi-Nage","Harai-Goshi"]'::jsonb, 'Uki-Goshi', 'technique'),\n('cinza-azul', 'Qual nova técnica de Osae-Komi-Waza é adicionada na faixa Cinza/Azul?', '["Kuzure-Kesa-Gatame","Tate-Shiho-Gatame","Yoko-Shiho-Gatame","Kami-Shiho-Gatame"]'::jsonb, 'Yoko-Shiho-Gatame', 'technique'),\n('cinza-azul', 'Como os amortecimentos de quedas (Ukemi) devem ser demonstrados no exame para Cinza/Azul?', '["Deitado","Agachado","Todos em movimento","Em salto"]'::jsonb, 'Todos em movimento', 'technique'),\n('azul', 'Qual a idade mínima exigida para a faixa Azul?', '["6 (seis) anos","7 (sete) anos","8 (oito) anos","9 (nove) anos"]'::jsonb, '7 (sete) anos', 'history'),\n('azul', 'Quando foi fundada a Kodokan?', '["Maio de 1860","Maio de 1882","Outubro de 1860","Maio de 1938"]'::jsonb, 'Maio de 1882', 'history'),\n('azul', 'Qual arte marcial deu origem ao Judô?', '["Karate-Do","Kendo","Ju Jutsu","Aikido"]'::jsonb, 'Ju Jutsu', 'history'),\n('azul', 'Complete o princípio do Judô cobrado na faixa Azul: ''Quem teme perder...''', '["...não se aperfeiçoa.","...já está vencido.","...nunca ganha.","...deve treinar mais."]'::jsonb, '...já está vencido.', 'history'),\n('azul', 'O que significa ''Happo-Kuzushi''?', '["Oito formas de imobilização","Oito quedas básicas","Oito direções de desequilíbrio","Oito pegadas no judogi"]'::jsonb, 'Oito direções de desequilíbrio', 'vocab'),\n('azul', 'Qual é a palavra que designa o ''Casaco'' do uniforme de Judô?', '["Shitabaki","Obi","Zori","Uwagi"]'::jsonb, 'Uwagi', 'vocab'),\n('azul', 'Qual é a palavra que designa a ''Calça'' do uniforme de Judô?', '["Shitabaki","Uwagi","Zori","Obi"]'::jsonb, 'Shitabaki', 'vocab'),\n('azul', 'Qual é a palavra que designa o ''Chinelo'' no vocabulário de Judô?', '["Shitabaki","Uwagi","Zori","Obi"]'::jsonb, 'Zori', 'vocab'),\n('azul', 'Qual técnica de projeção é introduzida pela primeira vez no exame da faixa Azul?', '["De-Ashi-Harai","O-Goshi","Tai-Otoshi","Uchi-Mata"]'::jsonb, 'De-Ashi-Harai', 'technique'),\n('azul', 'Qual sequência de técnicas (Renraku-Henka-Waza) é exigida no exame da faixa Azul?', '["O-Soto-Gari > Kesa-Gatame","O-Uchi-Gari > O-Goshi","O-Uchi-Gari > De-Ashi-Harai","Hiza-Guruma > Seoi-Nage"]'::jsonb, 'O-Uchi-Gari > De-Ashi-Harai', 'technique'),\n('azul', 'Na faixa Azul, além de projetar, o judoca deve demonstrar quantas viradas com o Uke de barriga para baixo em Osae-Komi-Waza?', '["1 (uma) virada","2 (duas) viradas","3 (três) viradas","4 (quatro) viradas"]'::jsonb, '2 (duas) viradas', 'technique'),\n('azul-amarela', 'Qual a idade mínima exigida para a faixa Azul/Amarela?', '["6 (seis) anos","7 (sete) anos","8 (oito) anos","9 (nove) anos"]'::jsonb, '8 (oito) anos', 'history'),\n('azul-amarela', 'Qual é a data e o local de nascimento de Jigoro Kano?', '["4 de Maio de 1938, Cairo","28 de Outubro de 1860, Mikage","Maio de 1882, Kodokan","18 de Junho de 1908, Tóquio"]'::jsonb, '28 de Outubro de 1860, Mikage, JAPÃO', 'history'),\n('azul-amarela', 'Complete o princípio cobrado na faixa Azul/Amarela: ''Conhecer-se é dominar-se...''', '["...e dominar os outros.","...dominar-se é triunfar.","...é o uso suave da energia.","...quem teme perder já está vencido."]'::jsonb, '...dominar-se é triunfar.', 'history'),\n('azul-amarela', 'Quais são as graduações que pertencem à categoria ''Kodansha'' na ordem das faixas?', '["Branca a Azul/Amarela","Laranja a Marrom","Faixas Pretas do 1º ao 5º Dan","Faixa Vermelha/Branca e Vermelha, 6º ao 10º Dan"]'::jsonb, 'Faixa Vermelha/Branca e Vermelha, 6º ao 10º Dan', 'history'),\n('azul-amarela', 'O que significa ''Uchi-Komi''?', '["Competição","Treinamento livre","Treinamento de entrada de técnicas","Área de competição"]'::jsonb, 'Treinamento de entrada de técnicas', 'vocab'),\n('azul-amarela', 'O que significa ''Randori''?', '["Treinamento livre","Área de treinamento","Treinamento de entrada","Competição"]'::jsonb, 'Treinamento livre', 'vocab'),\n('azul-amarela', 'O que é ''Shiai'' no vocabulário de Judô?', '["Treinamento livre","Competição","Área de treinamento","Meditação"]'::jsonb, 'Competição', 'vocab'),\n('azul-amarela', 'O que significa ''Shiai-Jô''?', '["Área de competição","Área de treinamento","Treinamento livre","Competição"]'::jsonb, 'Área de competição', 'vocab'),\n('azul-amarela', 'Qual é o termo para ''Postura Natural'' em Judô?', '["Jigo-Hon-Tai","Shizen-Hon-Tai","Ayumi-Ashi","Tsugi-Ashi"]'::jsonb, 'Shizen-Hon-Tai', 'technique'),\n('azul-amarela', 'Qual é o termo para ''Postura Defensiva Básica''?', '["Shizen-Hon-Tai","Jigo-Hon-Tai","Migi-Shizen-Tai","Ayumi-Ashi"]'::jsonb, 'Jigo-Hon-Tai', 'technique'),\n('azul-amarela', 'Qual nova técnica de Nage-Waza é introduzida na faixa Azul/Amarela?', '["O-Goshi","Tai-Otoshi","Seoi-Nage","Tomoe-Nage"]'::jsonb, 'O-Goshi', 'technique'),\n('azul-amarela', 'Qual técnica de Osae-Komi-Waza é adicionada ao exame na faixa Azul/Amarela?', '["Kesa-Gatame","Yoko-Shiho-Gatame","Kami-Shiho-Gatame","Tate-Shiho-Gatame"]'::jsonb, 'Kami-Shiho-Gatame', 'technique'),\n('azul-amarela', 'Qual contra-ataque (Kaeshi-Waza) é exigido na faixa Azul/Amarela?', '["O-Uchi-Gari > O-Goshi","O-Uchi-Gari > Seoi-Nage","Sasae-Tsuri-Komi-Ashi > De-Ashi-Harai","Uki-Goshi > Koshi-Guruma"]'::jsonb, 'O-Uchi-Gari > O-Goshi', 'technique'),\n('amarela', 'Quando e onde ocorreu a morte de Jigoro Kano?', '["28 de Outubro de 1860, Mikage","4 de maio de 1938 a bordo de um navio, voltando do Cairo","Maio de 1882 em Tóquio","Em 1954 no Rio de Janeiro"]'::jsonb, '4 de maio de 1938 a bordo de um navio, voltando do Cairo', 'history'),\n('amarela', 'Complete o princípio: ''O Judoca não se aperfeiçoa para lutar...''', '["...mas para usar a energia.","...luta para se aperfeiçoar.","...quem teme perder já está vencido.","...dominar-se é triunfar."]'::jsonb, '...luta para se aperfeiçoar.', 'history'),\n('amarela', 'O que significa ''Uke''?', '["Judoca ativo","Professor","Árbitro","Judoca passivo"]'::jsonb, 'Judoca passivo', 'vocab'),\n('amarela', 'O que significa ''Tori''?', '["Judoca passivo","Árbitro","Judoca ativo","Escola de Judô"]'::jsonb, 'Judoca ativo', 'vocab'),\n('amarela', 'O que é ''Ayumi-Ashi''?', '["Passadas sucessivas","Passadas normais","Esquiva rotatória","Postura defensiva"]'::jsonb, 'Passadas normais', 'technique'),\n('amarela', 'O que é ''Tsugi-Ashi''?', '["Passadas sucessivas","Passadas normais","Queda com rolamento","Saudação"]'::jsonb, 'Passadas sucessivas', 'technique'),\n('amarela', 'Qual nova técnica de Nage-Waza é exigida na faixa Amarela?', '["Seoi-Nage","Tomoe-Nage","Uchi-Mata","Harai-Goshi"]'::jsonb, 'Seoi-Nage', 'technique'),\n('amarela', 'Qual nova técnica de Osae-Komi-Waza é incluída na faixa Amarela?', '["Kami-Shiho-Gatame","Yoko-Shiho-Gatame","Ushiro-Kesa-Gatame","Kata-Gatame"]'::jsonb, 'Ushiro-Kesa-Gatame', 'technique'),\n('amarela', 'Qual técnica de Renraku-Henka-Waza é adicionada na faixa Amarela?', '["O-Uchi-Gari > De-Ashi-Harai","O-Soto-Gari > Kesa-Gatame","De-Ashi-Harai > O-Soto-Gari","Hiza-Guruma > Seoi-Nage"]'::jsonb, 'De-Ashi-Harai > O-Soto-Gari', 'technique'),\n('amarela', 'Qual contra-ataque (Kaeshi-Waza) novo é exigido na faixa Amarela?', '["O-Uchi-Gari > Seoi-Nage","O-Uchi-Gari > O-Goshi","Sasae-Tsuri-Komi-Ashi > De-Ashi-Harai","Uki-Goshi > Koshi-Guruma"]'::jsonb, 'O-Uchi-Gari > Seoi-Nage', 'technique'),\n('amarela', 'Na faixa Amarela, os movimentos ''Tsugi-Ashi'' assemelham-se à forma de andar de qual Kata?', '["Katame-no-Kata","Nage-no-Kata","Kime-no-Kata","Ju-no-Kata"]'::jsonb, 'Nage-no-Kata', 'technique'),\n('amarela-laranja', 'Onde e em que ano ocorreu o Primeiro Campeonato Brasileiro de Judô?', '["1954, no Rio de Janeiro","1964, em Tóquio","1965, em São Paulo","1972, em Munique"]'::jsonb, 'Ocorreu no ano de 1954, no Rio de Janeiro - RJ', 'history'),\n('amarela-laranja', 'O que significa o termo ''Ju''?', '["Caminho","Suave","Arte","Energia"]'::jsonb, 'Suave', 'vocab'),\n('amarela-laranja', 'O que significa o termo ''Do''?', '["Caminho","Suave","Energia","Mente"]'::jsonb, 'Caminho', 'vocab'),\n('amarela-laranja', 'Qual princípio significa ''Melhor uso da energia''?', '["Jita Kyoei","Seiryoku Zen''yo","Kuzushi","Tsukuri"]'::jsonb, 'Seiryoku Zen''yo', 'history'),\n('amarela-laranja', 'O que é ''Tai-Sabaki''?', '["Técnica de projeção","Movimentos rotatórios do corpo (esquiva)","Técnica de estrangulamento","Imobilização de ombro"]'::jsonb, 'Movimento rotatórios do corpo (esquiva)', 'technique'),\n('amarela-laranja', 'O que significa ''Mae-Sabaki'' no Tai-Sabaki?', '["Movimento para frente","Movimento para trás","Movimento para frente com giro","Movimento lateral"]'::jsonb, 'Movimento para frente', 'technique'),\n('amarela-laranja', 'O que significa ''Ushiro-Mawari-Sabaki''?', '["Movimento para trás com giro","Movimento para frente com giro","Movimento para trás simples","Passada lateral"]'::jsonb, 'Movimento para trás com giro', 'technique'),\n('amarela-laranja', 'Qual é a primeira técnica de Nage-Waza inserida na lista da faixa Amarela/Laranja?', '["Tai-Otoshi","Hiza-Guruma","Harai-Goshi","Uchi-Mata"]'::jsonb, 'Hiza-Guruma', 'technique'),\n('amarela-laranja', 'Além do Hiza-Guruma, qual outra técnica de Nage-Waza é exigida para Amarela/Laranja?', '["Sasae-Tsuri-Komi-Ashi","Tomoe-Nage","Kata-Guruma","O-Guruma"]'::jsonb, 'Sasae-Tsuri-Komi-Ashi', 'technique'),\n('amarela-laranja', 'Qual técnica de imobilização é introduzida na faixa Amarela/Laranja?', '["Ushiro-Kesa-Gatame","Tate-Shiho-Gatame","Kata-Gatame","Ura-Gatame"]'::jsonb, 'Tate-Shiho-Gatame', 'technique'),\n('amarela-laranja', 'Qual sequência (Renraku-Henka-Waza) é adicionada na faixa Amarela/Laranja?', '["O-Soto-Gari > Kesa-Gatame","De-Ashi-Harai > O-Soto-Gari","Hiza-Guruma > Seoi-Nage","Uchi-Mata > Ko-Uchi-Gari"]'::jsonb, 'Hiza-Guruma > Seoi-Nage', 'technique'),\n('laranja', 'Quando foi a primeira vez que o Judô foi incluso nos Jogos Olímpicos como teste?', '["1954 em Tóquio","1964 em Tóquio","1972 em Munique","1956 no Japão"]'::jsonb, 'A primeira vez em 1964, nas olimpíadas de Tóquio', 'history'),\n('laranja', 'Complete o princípio do Judô: ''Somente se aproxima da perfeição...''', '["...quem domina as técnicas de sacrifício.","...quem conhece a história do esporte.","...quem a procura com constância, sabedoria e sobretudo, humildade.","...quem vence a própria ignorância."]'::jsonb, '...quem a procura com constância, sabedoria e sobretudo, humildade.', 'history'),\n('laranja', 'Qual é a fase de ''Desequilíbrio'' da projeção?', '["Tsukuri","Kake","Kuzushi","Mokuso"]'::jsonb, 'Kuzushi', 'vocab'),\n('laranja', 'Qual é a fase de ''Preparação'' da projeção?', '["Kuzushi","Tsukuri","Kake","Migi"]'::jsonb, 'Tsukuri', 'vocab'),\n('laranja', 'Qual é a fase de ''Aplicação'' da projeção?', '["Kuzushi","Tsukuri","Kake","Hidari"]'::jsonb, 'Kake', 'vocab'),\n('laranja', 'O que significam ''Migi'' e ''Hidari'', respectivamente?', '["Direito e Esquerdo","Esquerdo e Direito","Frente e Trás","Ativo e Passivo"]'::jsonb, 'Lado direito e Lado esquerdo', 'vocab'),\n('laranja', 'O que é Mokuso?', '["Arbitragem","Imobilização","Meditação","Projeção"]'::jsonb, 'Meditação', 'vocab'),\n('laranja', 'Qual dessas técnicas de projeção (Nage-Waza) é inserida no exame da faixa Laranja?', '["Harai-Goshi","Kata-Guruma","Tomoe-Nage","Ura-Nage"]'::jsonb, 'Harai-Goshi', 'technique'),\n('laranja', 'A técnica Tai-Otoshi se encaixa em qual categoria introduzida na faixa Laranja?', '["Osae-Komi-Waza","Shime-Waza","Nage-Waza","Ukemi"]'::jsonb, 'Nage-Waza', 'technique'),\n('laranja', 'Qual técnica de imobilização é introduzida na faixa Laranja?', '["Kuzure-Kami-Shiho-Gatame","Ura-Gatame","Kata-Gatame","Uki-Gatame"]'::jsonb, 'Kuzure-Kami-Shiho-Gatame', 'technique'),\n('laranja', 'Qual contra-ataque (Kaeshi-Waza) é adicionado no exame da Laranja?', '["Uki-Goshi > Koshi-Guruma","O-Uchi-Gari > Tomoe-Nage","Koshi-Guruma > Utsuri-Goshi","Harai-Goshi > Ushiro-Goshi"]'::jsonb, 'Uki-Goshi > Koshi-Guruma', 'technique'),\n('verde', 'Onde ocorreu o Primeiro Campeonato Mundial de Judô, em 1956?', '["França","Brasil","Japão","Alemanha"]'::jsonb, 'Em 1956 no Japão.', 'history'),\n('verde', 'Em quais anos, listados na matéria, o Brasil sediou Campeonatos Mundiais de Judô?', '["1954, 1964, 1972","1965, 2007, 2013","1982, 1990, 2000","1972, 1980, 2007"]'::jsonb, '1965, 2007, 2013', 'history'),\n('verde', 'Complete o princípio da faixa Verde: ''A única vitória que perdura...''', '["...é a conquista da faixa preta.","...é a que se conquista sobre o adversário.","...é a que se conquista sobre a própria ignorância.","...é a vitória nos Jogos Olímpicos."]'::jsonb, '...é a que se conquista sobre a própria ignorância.', 'history'),\n('verde', 